SELECT (SELECT HOMEPAGE_NAME FROM CMS_HOMEPAGE C WHERE C.HOMEPAGE_ID = A.HOMEPAGE_ID) AS HOMEPAGE_NAME, A.HOMEPAGE_ID, A.REQ_IDX,REQ_NAME, A.PHONE,A.CELL_PHONE, A.APPLY_ID,A.LOCKER_IDX, A.ADD_DATE, A.ADD_ID, A.MOD_DATE, A.MOD_ID, A.DELETE_YN, A.LOCKER_PRE_IDX, B.LOCKER_PRE_NAME, B.START_DATE, B.END_DATE, A.MEMBER_KEY, C.LOCKER_NAME FROM LOCKER_REQ A, LOCKER_PRE B, LOCKER C WHERE A.HOMEPAGE_ID = B.HOMEPAGE_ID AND A.LOCKER_PRE_IDX = B.LOCKER_PRE_IDX AND A.HOMEPAGE_ID = C.HOMEPAGE_ID AND A.LOCKER_PRE_IDX = C.LOCKER_PRE_IDX AND A.LOCKER_IDX = C.LOCKER_IDX AND A.HOMEPAGE_ID = #{homepage_id} AND A.DELETE_YN = 'N' AND A.LOCKER_PRE_IDX = #{locker_pre_idx}
AND A.REQ_NAME LIKE '%'||#{search_text}||'%'
ORDER BY LPAD(C.LOCKER_NAME, 50)

